import{_ as i,C as d,o as a,c as n,j as t,a as o,b as l,w as s,E as c,a3 as p,a2 as h}from"./chunks/framework.DGX-GXGI.js";const T=JSON.parse('{"title":"Agent Steps","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/agent-steps.md","filePath":"concepts/agent-steps.md"}'),u={name:"concepts/agent-steps.md"};function g(m,e,b,f,k,E){const r=d("Mermaid");return a(),n("div",null,[e[1]||(e[1]=t("h1",{id:"agent-steps",tabindex:"-1"},[o("Agent Steps "),t("a",{class:"header-anchor",href:"#agent-steps","aria-label":'Permalink to "Agent Steps"'},"​")],-1)),e[2]||(e[2]=t("p",null,[o("An "),t("strong",null,"agent step"),o(" is the atomic unit of execution in a workflow. Each step runs inside an agent worker, creates a Copilot session, sends a rendered prompt, and writes the result back to the database. This page explains every phase of step execution in detail.")],-1)),e[3]||(e[3]=t("h2",{id:"execution-pipeline",tabindex:"-1"},[o("Execution Pipeline "),t("a",{class:"header-anchor",href:"#execution-pipeline","aria-label":'Permalink to "Execution Pipeline"'},"​")],-1)),(a(),l(p,null,{default:s(()=>[c(r,{id:"mermaid-9",class:"mermaid",graph:"graph%20TB%0A%20%20%20%20START%5BAgent%20Worker%20picks%20up%20step%5D%20--%3E%20LOAD%5B1.%20Load%20step%20config%20from%20DB%5D%0A%20%20%20%20LOAD%20--%3E%20VARS%5B2.%20Resolve%203-tier%20variables%5D%0A%20%20%20%20VARS%20--%3E%20WORKSPACE%5B3.%20Prepare%20agent%20workspace%3Cbr%2F%3EGit%20clone%20or%20DB%20read%5D%0A%20%20%20%20WORKSPACE%20--%3E%20RENDER%5B4.%20Render%20prompt%20template%3Cbr%2F%3EJinja2%20%2F%20Nunjucks%5D%0A%20%20%20%20RENDER%20--%3E%20LOCK%5B5.%20Acquire%20session%20lock%3Cbr%2F%3ERedis%20SETNX%20per%20agent%5D%0A%20%20%20%20LOCK%20--%3E%20SESSION%5B6.%20Create%20Copilot%20session%3Cbr%2F%3Eagent%20%2B%20skills%20%2B%20tools%20%2B%20MCP%5D%0A%20%20%20%20SESSION%20--%3E%20SEND%5B7.%20Send%20prompt%20%2B%20wait%20for%20response%5D%0A%20%20%20%20SEND%20--%3E%20WRITE%5B8.%20Write%20output%20%2B%20reasoning%20trace%5D%0A%20%20%20%20WRITE%20--%3E%20CLEANUP%5B9.%20Cleanup%3A%20MCP%2C%3Cbr%2F%3Eworkspace%2C%20lock%5D%0A%0A%20%20%20%20style%20START%20fill%3A%23FF9800%2Ccolor%3A%23fff%0A%20%20%20%20style%20SESSION%20fill%3A%239C27B0%2Ccolor%3A%23fff%0A%20%20%20%20style%20WRITE%20fill%3A%234CAF50%2Ccolor%3A%23fff%0A"})]),fallback:s(()=>[...e[0]||(e[0]=[o(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=h(`<div class="mermaid-source" data-mermaid-source=""></div><h2 id="_1-load-step-configuration" tabindex="-1">1. Load Step Configuration <a class="header-anchor" href="#_1-load-step-configuration" aria-label="Permalink to &quot;1. Load Step Configuration&quot;">​</a></h2><p>The worker reads from the database:</p><table tabindex="0"><thead><tr><th>Record</th><th>Source Table</th><th>Key Fields</th></tr></thead><tbody><tr><td>Step execution</td><td><code>step_executions</code></td><td><code>id</code>, <code>stepOrder</code>, <code>status</code></td></tr><tr><td>Workflow execution</td><td><code>workflow_executions</code></td><td><code>workflowId</code>, <code>userId</code>, <code>triggerMetadata</code></td></tr><tr><td>Workflow</td><td><code>workflows</code></td><td><code>defaultAgentId</code>, <code>defaultModel</code>, <code>defaultReasoningEffort</code>, <code>workspaceId</code></td></tr><tr><td>Step definition</td><td><code>workflow_steps</code></td><td><code>promptTemplate</code>, <code>agentId</code>, <code>model</code>, <code>reasoningEffort</code>, <code>timeoutSeconds</code></td></tr><tr><td>Agent</td><td><code>agents</code></td><td><code>sourceType</code>, <code>gitRepoUrl</code>, <code>gitBranch</code>, <code>agentFilePath</code>, <code>skillsPaths</code>, <code>mcpJsonTemplate</code>, <code>builtinToolsEnabled</code></td></tr></tbody></table><p>The agent for the step is resolved in order:</p><ol><li>Step-level agent override (if set)</li><li>Workflow&#39;s default agent</li></ol><h2 id="_2-variable-resolution-3-tier-override" tabindex="-1">2. Variable Resolution (3-Tier Override) <a class="header-anchor" href="#_2-variable-resolution-3-tier-override" aria-label="Permalink to &quot;2. Variable Resolution (3-Tier Override)&quot;">​</a></h2><p>Variables are loaded from three scopes and merged with higher scopes overriding lower ones:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Workspace Variables (lowest) → User Variables → Agent Variables (highest)</span></span></code></pre></div><p>Each variable has a <code>variableType</code> (<code>credential</code> or <code>property</code>) and an optional <code>injectAsEnvVariable</code> flag:</p><ul><li><strong>Credentials</strong> → available as <span><code>{{ credentials.KEY }}</code></span> in templates</li><li><strong>Properties</strong> → available as <span><code>{{ properties.KEY }}</code></span> in templates</li><li><strong>Env-injected</strong> → written to a <code>.env</code> file in the agent workspace directory</li></ul><p>All values are stored encrypted (AES-256-GCM) and decrypted at resolution time. For full details on scoping and priority, see <a href="/open-agent-orchestra/concepts/variables.html">Variables</a>.</p><h2 id="_3-prepare-agent-workspace" tabindex="-1">3. Prepare Agent Workspace <a class="header-anchor" href="#_3-prepare-agent-workspace" aria-label="Permalink to &quot;3. Prepare Agent Workspace&quot;">​</a></h2><p>The workspace is where agent instructions and skills are loaded from. Two source types are supported:</p><h3 id="git-repository-sourcetype-github" tabindex="-1">Git Repository (<code>sourceType: &#39;github&#39;</code>) <a class="header-anchor" href="#git-repository-sourcetype-github" aria-label="Permalink to &quot;Git Repository (\`sourceType: &#39;github&#39;\`)&quot;">​</a></h3><ol><li>Clone the repository to a temporary directory using <code>git clone --depth 1</code></li><li>If a private repo, authenticate via <code>GIT_ASKPASS</code> with the encrypted GitHub token (resolved from a credential reference or inline token)</li><li>Optionally checkout a specific branch (<code>gitBranch</code>)</li><li>Read the <strong>agent markdown file</strong> from <code>agentFilePath</code> (e.g., <code>agents/data-analyst.md</code>)</li><li>Read <strong>skill files</strong> from explicit paths (<code>skillsPaths</code>) or scan a directory (<code>skillsDirectory</code>) for all <code>.md</code> files</li><li>Return the agent markdown, skill contents, and a temporary workdir path</li></ol><h3 id="database-editor-sourcetype-database" tabindex="-1">Database Editor (<code>sourceType: &#39;database&#39;</code>) <a class="header-anchor" href="#database-editor-sourcetype-database" aria-label="Permalink to &quot;Database Editor (\`sourceType: &#39;database&#39;\`)&quot;">​</a></h3><ol><li>Query <code>agent_files</code> table for all files belonging to the agent</li><li>The file marked <code>isMainFile: true</code> becomes the agent markdown</li><li>Other files become skills</li><li>Create a temporary directory and write files to disk (for MCP servers that need a filesystem)</li></ol><p>After execution, the temporary workspace is cleaned up automatically.</p><h2 id="_4-jinja2-prompt-rendering" tabindex="-1">4. Jinja2 Prompt Rendering <a class="header-anchor" href="#_4-jinja2-prompt-rendering" aria-label="Permalink to &quot;4. Jinja2 Prompt Rendering&quot;">​</a></h2><p>Step prompts are Jinja2 templates rendered with <a href="https://mozilla.github.io/nunjucks/" target="_blank" rel="noreferrer">Nunjucks</a> (a JavaScript Jinja2-compatible engine).</p><h3 id="available-template-variables" tabindex="-1">Available Template Variables <a class="header-anchor" href="#available-template-variables" aria-label="Permalink to &quot;Available Template Variables&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Variable</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><span><code>{{ precedent_output }}</code></span></td><td><code>string</code></td><td>Output from the previous step (empty for step 1 by default)</td></tr><tr><td><span><code>{{ properties.KEY }}</code></span></td><td><code>string</code></td><td>Property value from the 3-tier merged map</td></tr><tr><td><span><code>{{ credentials.KEY }}</code></span></td><td><code>string</code></td><td>Credential value from the 3-tier merged map</td></tr><tr><td><span><code>{{ env.KEY }}</code></span></td><td><code>string</code></td><td>Environment-injected variable value</td></tr><tr><td><span><code>{{ inputs.KEY }}</code></span></td><td><code>string</code></td><td>Webhook parameter / manual run input value</td></tr></tbody></table><p>For the full reference, see <a href="/open-agent-orchestra/reference/template-variables.html">Template Variables</a>.</p><h3 id="jinja2-features" tabindex="-1">Jinja2 Features <a class="header-anchor" href="#jinja2-features" aria-label="Permalink to &quot;Jinja2 Features&quot;">​</a></h3><p>Full Jinja2 syntax is supported — conditionals, loops, filters, and expressions:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Analyze the market for {{ properties.MARKET_SYMBOL }}.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Current risk limit: {{ properties.MAX_RISK_PERCENT }}%</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{% if precedent_output %}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Previous analysis:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{{ precedent_output }}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{% endif %}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{% for symbol in properties.WATCHLIST.split(&#39;,&#39;) %}</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Check {{ symbol | trim }}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{% endfor %}</span></span></code></pre></div><h3 id="precedent-output" tabindex="-1">Precedent Output <a class="header-anchor" href="#precedent-output" aria-label="Permalink to &quot;Precedent Output&quot;">​</a></h3><p>For <strong>step 1</strong>, precedent output is an empty string by default.</p><p>For <strong>step N</strong> (N &gt; 1), precedent output is the <code>output</code> field of step N-1&#39;s execution record.</p><blockquote><p><strong>Tip:</strong> Use <span><code>{{ inputs.KEY }}</code></span> to pass trigger parameters to step 1 instead of relying on precedent output.</p></blockquote><h2 id="_5-session-lock" tabindex="-1">5. Session Lock <a class="header-anchor" href="#_5-session-lock" aria-label="Permalink to &quot;5. Session Lock&quot;">​</a></h2><p>Before creating a Copilot session, the worker acquires a Redis distributed lock:</p><ul><li><strong>Key</strong>: <code>agent-session-lock:{agentId}</code></li><li><strong>TTL</strong>: 10 minutes (auto-expires if the worker crashes)</li><li><strong>Mechanism</strong>: <code>SET NX EX</code> — only one worker can hold the lock</li><li><strong>Release</strong>: Lua script (compare-and-delete) prevents releasing another worker&#39;s lock</li></ul><p>This ensures <strong>one active Copilot session per agent</strong> at any time.</p><p>If another execution is already using the same agent, the worker now waits briefly for the active session to finish before failing the step. This reduces false retry failures during session shutdown or near timeout boundaries.</p><h2 id="_6-copilot-session-setup" tabindex="-1">6. Copilot Session Setup <a class="header-anchor" href="#_6-copilot-session-setup" aria-label="Permalink to &quot;6. Copilot Session Setup&quot;">​</a></h2><p>The session is created with the GitHub Copilot SDK (<code>@github/copilot-sdk</code>):</p><h3 id="system-message" tabindex="-1">System Message <a class="header-anchor" href="#system-message" aria-label="Permalink to &quot;System Message&quot;">​</a></h3><p>The system message is assembled from:</p><ol><li><strong>Agent markdown</strong> — the main personality/instructions file</li><li><strong>Skills</strong> — additional markdown files appended under <code>## Agent Skills</code></li><li><strong>Guidelines</strong> — OAO appends autonomous-agent guidelines (explain reasoning, follow instructions)</li></ol><h3 id="tools" tabindex="-1">Tools <a class="header-anchor" href="#tools" aria-label="Permalink to &quot;Tools&quot;">​</a></h3><p>Tools are loaded in order and merged into a single array:</p><table tabindex="0"><thead><tr><th>Source</th><th>Description</th></tr></thead><tbody><tr><td><strong>Built-in tools</strong> (9 tools)</td><td><code>schedule_next_workflow_execution</code>, <code>manage_webhook_trigger</code>, <code>record_decision</code>, <code>memory_store</code>, <code>memory_retrieve</code>, <code>edit_workflow</code>, <code>read_variables</code>, <code>edit_variables</code>, <code>simple_http_request</code> — filtered by <code>builtinToolsEnabled</code></td></tr><tr><td><strong>MCP servers (JSON template)</strong></td><td>Agent&#39;s <code>mcpJsonTemplate</code> field rendered with Jinja2, parsed as JSON, and each server spawned.</td></tr></tbody></table><h3 id="model-resolution" tabindex="-1">Model Resolution <a class="header-anchor" href="#model-resolution" aria-label="Permalink to &quot;Model Resolution&quot;">​</a></h3><ol><li>Step-level <code>model</code> override (if set)</li><li>Workflow-level <code>defaultModel</code> (if set)</li><li><code>DEFAULT_AGENT_MODEL</code> env var (defaults to <code>gpt-4.1</code>)</li></ol><h3 id="reasoning-effort" tabindex="-1">Reasoning Effort <a class="header-anchor" href="#reasoning-effort" aria-label="Permalink to &quot;Reasoning Effort&quot;">​</a></h3><p>Optional. If set on the step or workflow, passed to the Copilot session for models that support it (<code>high</code>, <code>medium</code>, <code>low</code>).</p><h2 id="_7-prompt-execution" tabindex="-1">7. Prompt Execution <a class="header-anchor" href="#_7-prompt-execution" aria-label="Permalink to &quot;7. Prompt Execution&quot;">​</a></h2><p>The rendered prompt is sent to the Copilot session:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>session.sendAndWait({ prompt: resolvedPrompt }, timeoutMs)</span></span></code></pre></div><ul><li><strong>Timeout</strong>: Step-level <code>timeoutSeconds</code> (default: 300 seconds / 5 minutes)</li><li><strong>Permission handling</strong>: <code>approveAll</code> — all tool calls are auto-approved for workflow executions</li><li><strong>Tool call tracking</strong>: The worker listens to <code>tool.execution_start</code> events to build the reasoning trace</li></ul><h2 id="_8-write-results" tabindex="-1">8. Write Results <a class="header-anchor" href="#_8-write-results" aria-label="Permalink to &quot;8. Write Results&quot;">​</a></h2><p>After the session completes, the worker writes:</p><table tabindex="0"><thead><tr><th>Field</th><th>Table</th><th>Content</th></tr></thead><tbody><tr><td><code>output</code></td><td><code>step_executions</code></td><td>The Copilot response text</td></tr><tr><td><code>reasoningTrace</code></td><td><code>step_executions</code></td><td>JSONB with: model used, agent file, skills paths, approximate token counts, list of tool calls (name + args)</td></tr><tr><td><code>status</code></td><td><code>step_executions</code></td><td><code>completed</code> or <code>failed</code></td></tr><tr><td><code>agentQuotaUsage</code></td><td><code>agent_quota_usage</code></td><td>Approximate prompt/completion tokens + session count (upserted per agent per day)</td></tr><tr><td><code>creditUsage</code></td><td><code>credit_usage</code></td><td>Credits consumed per user per model per day (based on model&#39;s <code>creditCost</code>)</td></tr></tbody></table><h2 id="_9-cleanup" tabindex="-1">9. Cleanup <a class="header-anchor" href="#_9-cleanup" aria-label="Permalink to &quot;9. Cleanup&quot;">​</a></h2><p>After execution (success or failure), the worker cleans up:</p><ol><li><strong>MCP server processes</strong> — all spawned MCP servers are terminated</li><li><strong>Agent workspace</strong> — temporary Git clone directory deleted</li><li><strong>Session lock</strong> — Redis lock released (Lua compare-and-delete)</li></ol><p>The worker then returns to idle and picks up the next step from the BullMQ queue.</p>`,59))])}const A=i(u,[["render",g]]);export{T as __pageData,A as default};
